<?php function process($src, $dst) { @mkdir($dst, 0777, true); foreach(scandir($src) as $f) { if($f=="."||$f=="..") continue; $p=$src."/".$f; $t=$dst."/".str_replace(["Channel","channel"],["Group","group"],$f); if(is_dir($p)) process($p,$t); else file_put_contents($t, str_replace(["Channel","channel","Channels","channels"],["Group","group","Groups","groups"],file_get_contents($p))); } } process("app/Filament/Resources/Channels", "app/Filament/Resources/Groups");
